/* lexer.h -- PL/SW lexer for COR24 compiler */
/* Scans input buffer producing tokens */

#ifndef LEXER_H
#define LEXER_H

#include "token.h"

/* Lexer state */
char *lex_src;    /* source buffer pointer */
int   lex_pos;    /* current position in source */
int   lex_len;    /* length of source */

/* Initialize lexer with a source buffer */
void lex_init(char *src, int len) {
    lex_src = src;
    lex_pos = 0;
    lex_len = len;
    kw_init();
}

/* Peek at current character without advancing */
int lex_peek(void) {
    if (lex_pos >= lex_len) return 0;
    return lex_src[lex_pos];
}

/* Advance and return current character */
int lex_next(void) {
    if (lex_pos >= lex_len) return 0;
    int c = lex_src[lex_pos];
    lex_pos = lex_pos + 1;
    return c;
}

/* Peek at next character (one ahead) */
int lex_peek2(void) {
    if (lex_pos + 1 >= lex_len) return 0;
    return lex_src[lex_pos + 1];
}

/* Character classification */
int is_alpha(int c) {
    return (c >= 65 && c <= 90) || (c >= 97 && c <= 122) || c == 95;
}

int is_digit(int c) {
    return c >= 48 && c <= 57;
}

int is_alnum(int c) {
    return is_alpha(c) || is_digit(c);
}

int is_space(int c) {
    return c == 32 || c == 9 || c == 10 || c == 13;
}

/* Skip whitespace and comments */
void lex_skip(void) {
    while (lex_pos < lex_len) {
        int c = lex_peek();

        /* whitespace */
        if (is_space(c)) {
            lex_next();
            continue;
        }

        /* block comment: / * ... * / */
        if (c == 47 && lex_peek2() == 42) {
            lex_next(); /* skip / */
            lex_next(); /* skip * */
            while (lex_pos < lex_len) {
                if (lex_peek() == 42 && lex_peek2() == 47) {
                    lex_next(); /* skip * */
                    lex_next(); /* skip / */
                    break;
                }
                lex_next();
            }
            continue;
        }

        break;
    }
}

/* Scan the next token from input. Returns token type. */
int lex_scan(struct token *tok) {
    lex_skip();

    tok->ival = 0;
    tok->text[0] = 0;

    if (lex_pos >= lex_len) {
        tok->type = TOK_EOF;
        str_copy(tok->text, "EOF");
        return TOK_EOF;
    }

    int c = lex_peek();

    /* Identifier or keyword */
    if (is_alpha(c)) {
        int i = 0;
        while (lex_pos < lex_len && is_alnum(lex_peek()) && i < TOK_TEXT_MAX - 1) {
            tok->text[i] = lex_next();
            i = i + 1;
        }
        tok->text[i] = 0;
        tok->type = kw_lookup(tok->text);
        return tok->type;
    }

    /* Number */
    if (is_digit(c)) {
        int i = 0;
        int val = 0;
