    if (c == 94) { /* ^ */
        tok->type = TOK_CARET;
        str_copy(tok->text, "^");
        return TOK_CARET;
    }
    if (c == 126) { /* ~ */
        tok->type = TOK_TILDE;
        str_copy(tok->text, "~");
        return TOK_TILDE;
