    if (c == 33) { /* ! */
        if (lex_peek() == 61) { /* != */
            lex_next();
            tok->type = TOK_NE;
            str_copy(tok->text, "!=");
            return TOK_NE;
        }
        /* standalone ! -- treat as unknown, store text */
        tok->type = TOK_TILDE; /* reuse tilde for logical not */
        str_copy(tok->text, "!");
        return tok->type;
