        if (lex_peek() == 60) { /* << */
            lex_next();
            tok->type = TOK_SHL;
            str_copy(tok->text, "<<");
            return TOK_SHL;
        }
        tok->type = TOK_LT;
        str_copy(tok->text, "<");
        return TOK_LT;
