1	/* lexer.h -- PL/SW lexer for COR24 compiler */
2	/* Scans input buffer producing tokens */
3	
4	#ifndef LEXER_H
5	#define LEXER_H
6	
7	#include "token.h"
8	
9	/* Lexer state */
10	char *lex_src;    /* source buffer pointer */
11	int   lex_pos;    /* current position in source */
12	int   lex_len;    /* length of source */
13	
14	/* Initialize lexer with a source buffer */
15	void lex_init(char *src, int len) {
16	    lex_src = src;
17	    lex_pos = 0;
18	    lex_len = len;
19	    kw_init();
20	}
21	
22	/* Peek at current character without advancing */
23	int lex_peek(void) {
24	    if (lex_pos >= lex_len) return 0;
25	    return lex_src[lex_pos];
26	}
27	
28	/* Advance and return current character */
29	int lex_next(void) {
30	    if (lex_pos >= lex_len) return 0;
31	    int c = lex_src[lex_pos];
32	    lex_pos = lex_pos + 1;
33	    return c;
34	}
35	
36	/* Peek at next character (one ahead) */
37	int lex_peek2(void) {
38	    if (lex_pos + 1 >= lex_len) return 0;
39	    return lex_src[lex_pos + 1];
40	}
41	
42	/* Character classification */
43	int is_alpha(int c) {
44	    return (c >= 65 && c <= 90) || (c >= 97 && c <= 122) || c == 95;
45	}
46	
47	int is_digit(int c) {
48	    return c >= 48 && c <= 57;
49	}
50	
51	int is_alnum(int c) {
52	    return is_alpha(c) || is_digit(c);
53	}
54	
55	int is_space(int c) {
56	    return c == 32 || c == 9 || c == 10 || c == 13;
57	}
58	
59	/* Skip whitespace and comments */
60	void lex_skip(void) {
61	    while (lex_pos < lex_len) {
62	        int c = lex_peek();
63	
64	        /* whitespace */
65	        if (is_space(c)) {
66	            lex_next();
67	            continue;
68	        }
69	
70	        /* block comment: / * ... * / */
71	        if (c == 47 && lex_peek2() == 42) {
72	            lex_next(); /* skip / */
73	            lex_next(); /* skip * */
74	            while (lex_pos < lex_len) {
75	                if (lex_peek() == 42 && lex_peek2() == 47) {
76	                    lex_next(); /* skip * */
77	                    lex_next(); /* skip / */
78	                    break;
79	                }
80	                lex_next();
81	            }
82	            continue;
83	        }
84	
85	        break;
86	    }
87	}
88	
89	/* Scan the next token from input. Returns token type. */
90	int lex_scan(struct token *tok) {
91	    lex_skip();
92	
93	    tok->ival = 0;
94	    tok->text[0] = 0;
95	
96	    if (lex_pos >= lex_len) {
97	        tok->type = TOK_EOF;
98	        str_copy(tok->text, "EOF");
99	        return TOK_EOF;
100	    }
101	
102	    int c = lex_peek();
103	
104	    /* Identifier or keyword */
105	    if (is_alpha(c)) {
106	        int i = 0;
107	        while (lex_pos < lex_len && is_alnum(lex_peek()) && i < TOK_TEXT_MAX - 1) {
108	            tok->text[i] = lex_next();
109	            i = i + 1;
110	        }
111	        tok->text[i] = 0;
112	        tok->type = kw_lookup(tok->text);
113	        return tok->type;
114	    }
115	
116	    /* Number */
117	    if (is_digit(c)) {
118	        int i = 0;
119	        int val = 0;
120	        while (lex_pos < lex_len && is_digit(lex_peek()) && i < TOK_TEXT_MAX - 1) {
121	            int d = lex_next();
122	            tok->text[i] = d;
123	            val = val * 10 + (d - 48);
124	            i = i + 1;
125	        }
126	        tok->text[i] = 0;
127	        tok->type = TOK_NUM;
128	        tok->ival = val;
129	        return TOK_NUM;
130	    }
131	
132	    /* String literal (single-quoted) */
133	    if (c == 39) {
134	        lex_next(); /* skip opening quote */
135	        int i = 0;
136	        while (lex_pos < lex_len && lex_peek() != 39 && i < TOK_TEXT_MAX - 1) {
137	            tok->text[i] = lex_next();
138	            i = i + 1;
139	        }
140	        tok->text[i] = 0;
141	        if (lex_pos < lex_len && lex_peek() == 39) {
142	            lex_next(); /* skip closing quote */
143	        }
144	        tok->type = TOK_STRING;
145	        return TOK_STRING;
146	    }
147	
148	    /* Operators and punctuation */
149	    lex_next(); /* consume the character */
150	
151	    if (c == 43) { /* + */
152	        tok->type = TOK_PLUS;
153	        str_copy(tok->text, "+");
154	        return TOK_PLUS;
155	    }
156	    if (c == 45) { /* - */
157	        if (lex_peek() == 62) { /* -> */
158	            lex_next();
159	            tok->type = TOK_ARROW;
160	            str_copy(tok->text, "->");
161	            return TOK_ARROW;
162	        }
163	        tok->type = TOK_MINUS;
164	        str_copy(tok->text, "-");
165	        return TOK_MINUS;
166	    }
167	    if (c == 42) { /* * */
168	        tok->type = TOK_STAR;
169	        str_copy(tok->text, "*");
170	        return TOK_STAR;
171	    }
172	    if (c == 47) { /* / */
173	        tok->type = TOK_SLASH;
174	        str_copy(tok->text, "/");
175	        return TOK_SLASH;
176	    }
177	    if (c == 38) { /* & */
178	        tok->type = TOK_AMP;
179	        str_copy(tok->text, "&");
180	        return TOK_AMP;
181	    }
182	    if (c == 124) { /* | */
183	        tok->type = TOK_PIPE;
184	        str_copy(tok->text, "|");
185	        return TOK_PIPE;
186	    }
187	    if (c == 94) { /* ^ */
188	        tok->type = TOK_CARET;
189	        str_copy(tok->text, "^");
190	        return TOK_CARET;
191	    }
192	    if (c == 126) { /* ~ */
193	        tok->type = TOK_TILDE;
194	        str_copy(tok->text, "~");
195	        return TOK_TILDE;
196	    }
197	    if (c == 61) { /* = */
198	        tok->type = TOK_EQ;
199	        str_copy(tok->text, "=");
200	        return TOK_EQ;
201	    }
202	    if (c == 33) { /* ! */
203	        if (lex_peek() == 61) { /* != */
204	            lex_next();
205	            tok->type = TOK_NE;
206	            str_copy(tok->text, "!=");
207	            return TOK_NE;
208	        }
209	        /* standalone ! -- treat as unknown, store text */
210	        tok->type = TOK_TILDE; /* reuse tilde for logical not */
211	        str_copy(tok->text, "!");
212	        return tok->type;
213	    }
214	    if (c == 60) { /* < */
215	        if (lex_peek() == 61) { /* <= */
216	            lex_next();
217	            tok->type = TOK_LE;
218	            str_copy(tok->text, "<=");
219	            return TOK_LE;
220	        }
221	        if (lex_peek() == 60) { /* << */
222	            lex_next();
223	            tok->type = TOK_SHL;
224	            str_copy(tok->text, "<<");
225	            return TOK_SHL;
226	        }
227	        tok->type = TOK_LT;
228	        str_copy(tok->text, "<");
229	        return TOK_LT;
230	    }
231	    if (c == 62) { /* > */
232	        if (lex_peek() == 61) { /* >= */
233	            lex_next();
234	            tok->type = TOK_GE;
235	            str_copy(tok->text, ">=");
236	            return TOK_GE;
237	        }
238	        if (lex_peek() == 62) { /* >> */
239	            lex_next();
240	            tok->type = TOK_SHR;
241	            str_copy(tok->text, ">>");
242	            return TOK_SHR;
243	        }
244	        tok->type = TOK_GT;
245	        str_copy(tok->text, ">");
246	        return TOK_GT;
247	    }
248	    if (c == 40) { /* ( */
249	        tok->type = TOK_LPAREN;
250	        str_copy(tok->text, "(");
251	        return TOK_LPAREN;
252	    }
253	    if (c == 41) { /* ) */
254	        tok->type = TOK_RPAREN;
255	        str_copy(tok->text, ")");
256	        return TOK_RPAREN;
257	    }
258	    if (c == 44) { /* , */
259	        tok->type = TOK_COMMA;
260	        str_copy(tok->text, ",");
261	        return TOK_COMMA;
262	    }
263	    if (c == 59) { /* ; */
264	        tok->type = TOK_SEMI;
265	        str_copy(tok->text, ";");
266	        return TOK_SEMI;
267	    }
268	    if (c == 46) { /* . */
269	        tok->type = TOK_DOT;
270	        str_copy(tok->text, ".");
271	        return TOK_DOT;
272	    }
273	    if (c == 63) { /* ? */
274	        tok->type = TOK_QUESTION;
275	        str_copy(tok->text, "?");
276	        return TOK_QUESTION;
277	    }
278	    if (c == 37) { /* % */
279	        tok->type = TOK_PERCENT;
280	        str_copy(tok->text, "%");
281	        return TOK_PERCENT;
282	    }
283	
284	    /* Unknown character -- store it as text, return EOF to signal error */
285	    tok->text[0] = c;
286	    tok->text[1] = 0;
287	    tok->type = TOK_EOF;
288	    return TOK_EOF;
289	}
