/* lexer.h -- PL/SW lexer for COR24 compiler */
/* Scans input buffer producing tokens */

#ifndef LEXER_H
#define LEXER_H

#include "token.h"

/* Lexer state */
char *lex_src;    /* source buffer pointer */
int   lex_pos;    /* current position in source */
int   lex_len;    /* length of source */

/* Initialize lexer with a source buffer */
void lex_init(char *src, int len) {
    lex_src = src;
    lex_pos = 0;
    lex_len = len;
    kw_init();
}

/* Peek at current character without advancing */
int lex_peek(void) {
    if (lex_pos >= lex_len) return 0;
    return lex_src[lex_pos];
}

/* Advance and return current character */
int lex_next(void) {
    if (lex_pos >= lex_len) return 0;
    int c = lex_src[lex_pos];
    lex_pos = lex_pos + 1;
    return c;
}

/* Peek at next character (one ahead) */
int lex_peek2(void) {
    if (lex_pos + 1 >= lex_len) return 0;
    return lex_src[lex_pos + 1];
}

/* Character classification */
int is_alpha(int c) {
    return (c >= 65 && c <= 90) || (c >= 97 && c <= 122) || c == 95;
}

int is_digit(int c) {
    return c >= 48 && c <= 57;
}

int is_alnum(int c) {
    return is_alpha(c) || is_digit(c);
}

int is_space(int c) {
    return c == 32 || c == 9 || c == 10 || c == 13;
}

/* Skip whitespace and comments */
void lex_skip(void) {
    while (lex_pos < lex_len) {
        int c = lex_peek();

        /* whitespace */
        if (is_space(c)) {
            lex_next();
            continue;
        }

        /* block comment: / * ... * / */
        if (c == 47 && lex_peek2() == 42) {
            lex_next(); /* skip / */
            lex_next(); /* skip * */
            while (lex_pos < lex_len) {
                if (lex_peek() == 42 && lex_peek2() == 47) {
                    lex_next(); /* skip * */
                    lex_next(); /* skip / */
                    break;
                }
                lex_next();
            }
            continue;
        }

        break;
    }
}

/* Scan the next token from input. Returns token type. */
int lex_scan(struct token *tok) {
    lex_skip();

    tok->ival = 0;
    tok->text[0] = 0;

    if (lex_pos >= lex_len) {
        tok->type = TOK_EOF;
        str_copy(tok->text, "EOF");
        return TOK_EOF;
    }

    int c = lex_peek();

    /* Identifier or keyword */
    if (is_alpha(c)) {
        int i = 0;
        while (lex_pos < lex_len && is_alnum(lex_peek()) && i < TOK_TEXT_MAX - 1) {
            tok->text[i] = lex_next();
            i = i + 1;
        }
        tok->text[i] = 0;
        tok->type = kw_lookup(tok->text);
        return tok->type;
    }

    /* Number */
    if (is_digit(c)) {
        int i = 0;
        int val = 0;
        while (lex_pos < lex_len && is_digit(lex_peek()) && i < TOK_TEXT_MAX - 1) {
            int d = lex_next();
            tok->text[i] = d;
            val = val * 10 + (d - 48);
            i = i + 1;
        }
        tok->text[i] = 0;
        tok->type = TOK_NUM;
        tok->ival = val;
        return TOK_NUM;
    }

    /* String literal (single-quoted) */
    if (c == 39) {
        lex_next(); /* skip opening quote */
        int i = 0;
        while (lex_pos < lex_len && lex_peek() != 39 && i < TOK_TEXT_MAX - 1) {
            tok->text[i] = lex_next();
            i = i + 1;
        }
        tok->text[i] = 0;
        if (lex_pos < lex_len && lex_peek() == 39) {
            lex_next(); /* skip closing quote */
        }
        tok->type = TOK_STRING;
        return TOK_STRING;
    }

    /* Operators and punctuation */
    lex_next(); /* consume the character */

    if (c == 43) { /* + */
        tok->type = TOK_PLUS;
        str_copy(tok->text, "+");
        return TOK_PLUS;
    }
    if (c == 45) { /* - */
        if (lex_peek() == 62) { /* -> */
            lex_next();
            tok->type = TOK_ARROW;
            str_copy(tok->text, "->");
            return TOK_ARROW;
        }
        tok->type = TOK_MINUS;
        str_copy(tok->text, "-");
        return TOK_MINUS;
    }
    if (c == 42) { /* * */
        tok->type = TOK_STAR;
        str_copy(tok->text, "*");
        return TOK_STAR;
    }
    if (c == 47) { /* / */
        tok->type = TOK_SLASH;
        str_copy(tok->text, "/");
        return TOK_SLASH;
    }
    if (c == 38) { /* & */
        tok->type = TOK_AMP;
        str_copy(tok->text, "&");
        return TOK_AMP;
    }
    if (c == 124) { /* | */
        tok->type = TOK_PIPE;
        str_copy(tok->text, "|");
        return TOK_PIPE;
    }
    if (c == 94) { /* ^ */
        tok->type = TOK_CARET;
        str_copy(tok->text, "^");
        return TOK_CARET;
    }
    if (c == 126) { /* ~ */
        tok->type = TOK_TILDE;
        str_copy(tok->text, "~");
        return TOK_TILDE;
    }
    if (c == 61) { /* = */
        tok->type = TOK_EQ;
        str_copy(tok->text, "=");
        return TOK_EQ;
    }
    if (c == 33) { /* ! */
        if (lex_peek() == 61) { /* != */
            lex_next();
            tok->type = TOK_NE;
            str_copy(tok->text, "!=");
            return TOK_NE;
        }
        /* standalone ! -- treat as unknown, store text */
        tok->type = TOK_TILDE; /* reuse tilde for logical not */
        str_copy(tok->text, "!");
        return tok->type;
    }
    if (c == 60) { /* < */
        if (lex_peek() == 61) { /* <= */
            lex_next();
            tok->type = TOK_LE;
            str_copy(tok->text, "<=");
            return TOK_LE;
        }
        if (lex_peek() == 60) { /* << */
            lex_next();
            tok->type = TOK_SHL;
            str_copy(tok->text, "<<");
            return TOK_SHL;
        }
        tok->type = TOK_LT;
        str_copy(tok->text, "<");
        return TOK_LT;
    }
    if (c == 62) { /* > */
        if (lex_peek() == 61) { /* >= */
            lex_next();
            tok->type = TOK_GE;
            str_copy(tok->text, ">=");
            return TOK_GE;
        }
        if (lex_peek() == 62) { /* >> */
            lex_next();
            tok->type = TOK_SHR;
            str_copy(tok->text, ">>");
            return TOK_SHR;
        }
        tok->type = TOK_GT;
        str_copy(tok->text, ">");
        return TOK_GT;
    }
    if (c == 40) { /* ( */
        tok->type = TOK_LPAREN;
        str_copy(tok->text, "(");
        return TOK_LPAREN;
    }
    if (c == 41) { /* ) */
        tok->type = TOK_RPAREN;
        str_copy(tok->text, ")");
        return TOK_RPAREN;
    }
    if (c == 44) { /* , */
        tok->type = TOK_COMMA;
        str_copy(tok->text, ",");
        return TOK_COMMA;
    }
    if (c == 59) { /* ; */
        tok->type = TOK_SEMI;
        str_copy(tok->text, ";");
        return TOK_SEMI;
    }
    if (c == 46) { /* . */
        tok->type = TOK_DOT;
        str_copy(tok->text, ".");
        return TOK_DOT;
    }
    if (c == 63) { /* ? */
        tok->type = TOK_QUESTION;
        str_copy(tok->text, "?");
        return TOK_QUESTION;
    }
    if (c == 37) { /* % */
        tok->type = TOK_PERCENT;
        str_copy(tok->text, "%");
        return TOK_PERCENT;
    }

    /* Unknown character -- store it as text, return EOF to signal error */
    tok->text[0] = c;
    tok->text[1] = 0;
    tok->type = TOK_EOF;
    return TOK_EOF;
}

/* Current token state (globals to avoid stack pressure on COR24) */
int  cur_type;
int  cur_ival;
char cur_text[TOK_TEXT_MAX];

/* Copy scanned token into current-token globals */
void tok_save(struct token *t) {
    cur_type = t->type;
    cur_ival = t->ival;
    str_ncopy(cur_text, t->text, TOK_TEXT_MAX);
}

/* Print the current token for debugging */
void tok_print(void) {
    uart_putstr("  ");
    uart_putstr(tok_name(cur_type));
    if (cur_type == TOK_IDENT || cur_type == TOK_STRING) {
        uart_putstr("(");
        uart_putstr(cur_text);
        uart_putstr(")");
    } else if (cur_type == TOK_NUM) {
        uart_putstr("(");
        print_int(cur_ival);
        uart_putstr(")");
    }
    uart_putchar(10);
}

/* Scan next token into globals */
int lex_next_tok(void) {
    struct token t;
    int ty = lex_scan(&t);
    tok_save(&t);
    return ty;
}

/* Tokenize a source string and print all tokens */
void lex_dump(char *label, char *src) {
    uart_putstr("--- ");
    uart_putstr(label);
    uart_puts(" ---");

    lex_init(src, str_len(src));
    while (1) {
        lex_next_tok();
        tok_print();
        if (cur_type == TOK_EOF) break;
    }
}

