    if (c == 94) { lex_set(TOK_CARET, "^"); return TOK_CARET; }
    if (c == 126) { lex_set(TOK_TILDE, "~"); return TOK_TILDE; }
    if (c == 61) { lex_set(TOK_EQ, "="); return TOK_EQ; }
    if (c == 40) { lex_set(TOK_LPAREN, "("); return TOK_LPAREN; }
    if (c == 41) { lex_set(TOK_RPAREN, ")"); return TOK_RPAREN; }
    if (c == 44) { lex_set(TOK_COMMA, ","); return TOK_COMMA; }
    if (c == 59) { lex_set(TOK_SEMI, ";"); return TOK_SEMI; }
    if (c == 46) { lex_set(TOK_DOT, "."); return TOK_DOT; }
    if (c == 63) { lex_set(TOK_QUESTION, "?"); return TOK_QUESTION; }
    if (c == 37) { lex_set(TOK_PERCENT, "%"); return TOK_PERCENT; }

    if (c == 45) { /* - */
        if (lex_peek() == 62) {
            lex_advance();
            lex_set(TOK_ARROW, "->");
            return TOK_ARROW;
        }
        lex_set(TOK_MINUS, "-");
        return TOK_MINUS;
    }
    if (c == 33) { /* ! */
        if (lex_peek() == 61) {
            lex_advance();
            lex_set(TOK_NE, "!=");
            return TOK_NE;
        }
        lex_set(TOK_TILDE, "!");
        return TOK_TILDE;
    }
    if (c == 60) { /* < */
        if (lex_peek() == 61) {
            lex_advance();
            lex_set(TOK_LE, "<=");
            return TOK_LE;
        }
        if (lex_peek() == 60) {
            lex_advance();
            lex_set(TOK_SHL, "<<");
            return TOK_SHL;
        }
        lex_set(TOK_LT, "<");
        return TOK_LT;
    }
    if (c == 62) { /* > */
        if (lex_peek() == 61) {
            lex_advance();
            lex_set(TOK_GE, ">=");
            return TOK_GE;
        }
        if (lex_peek() == 62) {
            lex_advance();
            lex_set(TOK_SHR, ">>");
            return TOK_SHR;
        }
        lex_set(TOK_GT, ">");
        return TOK_GT;
    }

    /* Unknown character */
    cur_text[0] = c;
    cur_text[1] = 0;
    cur_type = TOK_EOF;
    return TOK_EOF;
}

/* Print the current token for debugging */
void tok_print(void) {
    uart_putstr("  ");
    uart_putstr(tok_name(cur_type));
    if (cur_type == TOK_IDENT || cur_type == TOK_STRING) {
        uart_putstr("(");
        uart_putstr(cur_text);
        uart_putstr(")");
    } else if (cur_type == TOK_NUM) {
        uart_putstr("(");
        print_int(cur_ival);
        uart_putstr(")");
    }
    uart_putchar(10);
}

/* Tokenize a source string and print all tokens */
void lex_dump(char *label, char *src) {
    uart_putstr("--- ");
    uart_putstr(label);
    uart_puts(" ---");

    lex_init(src, str_len(src));
    while (1) {
        lex_scan();
        tok_print();
        if (cur_type == TOK_EOF) break;
    }
}

